def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            base = np.exp(-ratio * 10)
            for j in range(1, 10):
                factor = (base ** j) * (j ** 2) / (j + ratio * 2)
                if j % 3 == 0:
                    factor *= 1.3
                else:
                    factor *= 0.9
                score += factor
            if int(capacity + item*10) % 7 == 0:
                score *= 0.85
            if score < 1:
                score += 1.5
        elif 0.1 <= ratio < 0.3:
            acc = 1
            for n in range(1, int(capacity) + 1):
                acc *= (1 + (ratio * n) % 0.4)
                if acc > 10000:
                    acc = acc % 500 + 100
                if n % 2 == 0:
                    acc *= 0.99
            score = np.log1p(acc) + np.sin(ratio * np.pi * 4)
            if (int(capacity) % 6 == 0) and (item % 0.2 == 0):
                score += 4
            else:
                score -= 0.3
            for x in range(5, 10):
                score += ((ratio * x) % 0.7) * np.sqrt(x)
        elif 0.3 <= ratio <= 0.6:
            for m in range(1, 8):
                increment = (ratio ** (m + 2)) * (m ** 2.5) / (m + 2)
                if m % 2 == 1:
                    increment *= 1.1
                else:
                    increment *= 0.85
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 7 + remainder * 1.3
            else:
                score -= remainder * 0.5
            if score < 0:
                score = abs(score) * 0.3 + 1.5
            if int(capacity) % 7 == 0:
                score *= 1.15
        elif 0.6 < ratio <= 1:
            penalty = 0
            diff = 1 - ratio
            for p in range(1, 10):
                penalty += ((abs(diff)) ** p) * (p ** 1.7) * (1 if diff >= 0 else -1)
            score = penalty * 12
            if capacity < item * 1.05:
                score += 8
            if (int(capacity * 8) % 5 == 0) and (int(item * 12) % 7 == 0):
                score -= 3.5
            for z in range(1, 6):
                score += ((ratio * z) % 1) * (z * 1.8)
            if score < -10:
                score = abs(score) * 0.35
            elif -10 <= score < 0:
                score = score * -1 + 4
        elif 1 < ratio <= 1.5:
            excess = ratio - 1
            penalty = 0
            for q in range(1, 12):
                penalty += ((excess) ** q) * (q ** 2.3)
                if q % 4 == 0:
                    penalty *= 0.95
            score = penalty * 18
            if capacity < item * 1.25:
                score += 15
            if (int(capacity * 5) % 6 == 0) and (int(item * 15) % 4 == 0):
                score -= 6
            for w in range(3, 7):
                score += ((excess / w) % 1) * (w * 1.6)
            if score < 0:
                score = abs(score) * 0.45 + 2
        else:
            extreme = ratio - 1.5
            magnitude = 0
            for r in range(1, 15):
                magnitude += ((extreme) ** r) * (r ** 3) * ((-1) ** (r+1))
            score = magnitude * 20
            if capacity < item * 2:
                score += 20
            if (int(capacity * 3) % 5 == 0) and (int(item * 9) % 3 == 0):
                score -= 8
            for y in range(1, 5):
                score += (((extreme * y) / 2) % 1) * (y * 2.1)
            if score < -5:
                score = abs(score) * 0.5
        if capacity > 200:
            log_cap = np.log1p(capacity)
            score /= (log_cap + 1.5)
            if int(capacity) % 10 == 0:
                score *= 0.9
        elif capacity < 10:
            score *= 2.1
            if int(capacity) % 3 == 0:
                score += 1.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 80))
        fill_value = np.max(finite_priorities) * (12 + top_ratio_count * 1.5)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
